<span class="token comment">//@Deprecated \u4FEE\u9970\u67D0\u4E2A\u5143\u7D20\uFF0C\u6BD4\u5982\u4FEE\u9970\u67D0\u4E2A\u7C7B\uFF0C\u8868\u793A\u8BE5\u5143\u7D20\u5DF2\u7ECF\u8FC7\u65F6\u4E86</span>
